import React from "react";

const Apps = () => {
  const partnerApps = [
    {
      name: "Sentinel",
      desc: "Create powerful price alerts and basket orders.",
      icon: "🔔",
    },
    {
      name: "Streak",
      desc: "Algo trading and backtesting without coding.",
      icon: "📈",
    },
    {
      name: "Sensibull",
      desc: "Options trading strategy and analysis platform.",
      icon: "🎯",
    },
    {
      name: "Smallcase",
      desc: "Invest in professionally managed stock baskets.",
      icon: "💼",
    },
    {
      name: "GoldenPi",
      desc: "Invest in Bonds and Debentures online.",
      icon: "🪙",
    },
    {
      name: "Ditto",
      desc: "Insurance advice made simple and honest.",
      icon: "🛡️",
    },
  ];

  return (
    <div className="apps-container" style={{ padding: "40px" }}>
      <h3 className="title" style={{ marginBottom: "30px", fontSize: "24px" }}>
        Apps
      </h3>

      <div
        className="apps-grid"
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
          gap: "25px",
        }}
      >
        {partnerApps.map((app, index) => (
          <div
            key={index}
            className="app-card"
            style={{
              padding: "30px",
              border: "1px solid #f1f1f1",
              borderRadius: "10px",
              textAlign: "left",
              backgroundColor: "#fff",
              transition: "transform 0.2s, box-shadow 0.2s",
              cursor: "pointer",
              boxShadow: "0 2px 4px rgba(0,0,0,0.02)",
            }}
          >
            <div style={{ fontSize: "36px", marginBottom: "15px" }}>
              {app.icon}
            </div>
            <h4 style={{ margin: "0 0 10px 0", color: "#444" }}>{app.name}</h4>
            <p
              style={{
                color: "#888",
                fontSize: "14px",
                lineHeight: "1.5",
                margin: 0,
              }}
            >
              {app.desc}
            </p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Apps;
